### 3-3. Redis 캐싱 적용

**파일 경로:** `application/src/main/kotlin/com/maum/backend/service/user/UserService.kt`

```kotlin
// AFTER - Redis 캐시 적용

@Service
class UserService(
    private val userRepository: UserRepository,
    private val redisTemplate: RedisTemplate<String, UserEntity>
) {
    companion object {
        // 캐시 키 접두사
        private const val CACHE_PREFIX = "user:nickname:"
        // TTL: 닉네임은 자주 변경되지 않으므로 30분 설정
        private val CACHE_TTL = Duration.ofMinutes(30)
    }

    // BEFORE: 매번 DB 조회
    // fun findByNickname(nickname: String): UserEntity? =
    //     userRepository.findByNickname(nickname)

    // AFTER: Look-aside 캐시 패턴
    fun findByNickname(nickname: String): UserEntity? {
        val cacheKey = "$CACHE_PREFIX$nickname"

        // 1. Redis에서 먼저 조회
        val cached = redisTemplate.opsForValue().get(cacheKey)
        if (cached != null) return cached

        // 2. Cache Miss -> DB 조회
        val user = userRepository.findByNickname(nickname) ?: return null

        // 3. Redis에 캐시 저장
        redisTemplate.opsForValue().set(cacheKey, user, CACHE_TTL)
        return user
    }

    // 닉네임 변경 시 캐시 무효화
    fun updateNickname(userId: String, newNickname: String): UserEntity {
        val user = userRepository.findById(userId)
            .orElseThrow { IllegalArgumentException("사용자를 찾을 수 없습니다.") }

        val oldCacheKey = "$CACHE_PREFIX${user.nickname}"
        val newCacheKey = "$CACHE_PREFIX$newNickname"

        // 기존 캐시 삭제
        redisTemplate.delete(oldCacheKey)

        val updated = user.copy(nickname = newNickname)
        val saved = userRepository.save(updated)

        // 새 닉네임으로 캐시 저장
        redisTemplate.opsForValue().set(newCacheKey, saved, CACHE_TTL)

        return saved
    }
}
